// Dafny port of src/collections/linear_fifo.rs
//
// Rust-faithful intent: this keeps the same FIFO state (`buf`, `head`, `count`)
// and the same observable circular-buffer operations.  Dafny has no Rust slice
// borrowing, MaybeUninit, allocator trait dispatch, or by-reference writable
// slice API, so those Rust primitives are represented mechanically with a
// sequence-backed buffer plus small helper methods.

module LinearFifoPort {
  class LinearFifo<T(0)> {
    var buf: seq<T>
    var head: int
    var count: int
    var dynamic: bool
    var powers_of_two: bool
    var fill: T
    var model: seq<T>

    predicate Valid()
      reads this
    {
      0 <= count <= |buf| &&
      count == |model| &&
      0 <= head &&
      (|buf| == 0 ==> head == 0) &&
      (|buf| > 0 ==> head < |buf|)
    }

    constructor Init(capacity: nat, dynamic_: bool, powers_of_two_: bool)
      ensures Valid()
      ensures |buf| == capacity
      ensures head == 0 && count == 0
      ensures dynamic == dynamic_
      ensures powers_of_two == powers_of_two_
    {
      var d: T;
      d := *;
      fill := d;
      buf := seq(capacity, _ => d);
      head := 0;
      count := 0;
      model := [];
      dynamic := dynamic_;
      powers_of_two := powers_of_two_;
    }

    function capacity(): int
      reads this
      requires Valid()
    {
      |buf|
    }

    function readable_length(): int
      reads this
      requires Valid()
    {
      count
    }

    function writable_length(): int
      reads this
      requires Valid()
    {
      |buf| - count
    }

    function Wrap(idx: int): int
      reads this
      requires Valid()
      requires 0 <= idx
    {
      if |buf| == 0 then 0 else idx % |buf|
    }

    function ReadableModel(): seq<T>
      reads this
      requires Valid()
    {
      model
    }

    function ReadableFrom(pos: int, n: int): seq<T>
      reads this
      requires Valid()
      requires 0 <= n <= count
      requires n == 0 || |buf| > 0
      requires n == 0 || 0 <= pos < |buf|
      decreases n
    {
      if n == 0 then []
      else [buf[pos]] + ReadableFrom(Wrap(pos + 1), n - 1)
    }

    function FillValue(v: T, n: int): seq<T>
      requires 0 <= n
    {
      seq(n, _ => v)
    }

    function Fill(n: int): seq<T>
      reads this
      requires 0 <= n
    {
      FillValue(fill, n)
    }

    function WritableSliceLen(offset: int): int
      reads this
      requires Valid()
      requires 0 <= offset
    {
      if offset > |buf| || offset > writable_length() then 0
      else if head + offset + count < |buf| then |buf| - (head + offset + count)
      else if |buf| == 0 then 0
      else writable_length() - offset
    }

    method reset_head_if_empty()
      requires Valid()
      modifies this
      ensures Valid()
      ensures count == old(count)
      ensures |buf| == old(|buf|)
      ensures count == 0 ==> head == 0
    {
      if count == 0 {
        head := 0;
      }
    }

    method realign()
      requires Valid()
      modifies this
      ensures Valid()
      ensures head == 0
      ensures count == old(count)
      ensures |buf| == old(|buf|)
      ensures ReadableModel() == old(ReadableModel())
    {
      var r := ReadableModel();
      buf := r + Fill(|buf| - |r|);
      head := 0;
      count := |r|;
      model := r;
    }

    method shrink(size: nat)
      requires Valid()
      requires size >= count
      modifies this
      ensures Valid()
      ensures count == old(count)
      ensures ReadableModel() == old(ReadableModel())
      ensures dynamic ==> |buf| == size
      ensures !dynamic ==> |buf| == old(|buf|)
    {
      if dynamic {
        var r := ReadableModel();
        buf := r + Fill(size - |r|);
        head := 0;
        count := |r|;
        model := r;
      }
    }

    method ensure_total_capacity(size: nat) returns (ok: bool)
      requires Valid()
      modifies this
      ensures Valid()
      ensures count == old(count)
      ensures ReadableModel() == old(ReadableModel())
      ensures ok ==> |buf| >= size
      ensures !ok ==> !dynamic && old(|buf|) < size
    {
      if |buf| >= size {
        ok := true;
        return;
      }
      if dynamic {
        var r := ReadableModel();
        buf := r + Fill(size - |r|);
        head := 0;
        count := |r|;
        model := r;
        ok := true;
      } else {
        ok := false;
      }
    }

    method ensure_unused_capacity(size: nat) returns (ok: bool)
      requires Valid()
      modifies this
      ensures Valid()
      ensures count == old(count)
      ensures ReadableModel() == old(ReadableModel())
      ensures ok ==> writable_length() >= size
      ensures old(writable_length()) >= size ==> ok
    {
      if writable_length() >= size {
        ok := true;
      } else {
        ok := ensure_total_capacity(count + size);
      }
    }

    method readable_slice(offset: nat) returns (s: seq<T>)
      requires Valid()
      ensures Valid()
      ensures offset > old(count) ==> s == []
      ensures offset <= old(count) ==> s == old(ReadableModel())[offset..]
    {
      if offset > count {
        s := [];
      } else {
        s := ReadableModel()[offset..];
      }
    }

    method discard(n: nat)
      requires Valid()
      requires n <= count
      modifies this
      ensures Valid()
      ensures count == old(count) - n
      ensures |buf| == old(|buf|)
      ensures ReadableModel() == old(ReadableModel())[n..]
    {
      if |buf| == 0 {
        head := 0;
      } else {
        head := (head + n) % |buf|;
      }
      count := count - n;
      model := model[n..];
      if count == 0 && |buf| == 0 {
        head := 0;
      }
    }

